// Log lead to internal store (replace with DB later)
const lead = $input.first().json;

const logEntry = {
  timestamp: lead.timestamp,
  name: lead.name,
  phone: lead.phone,
  service: lead.priceRange.label,
  urgency: lead.urgency,
  priceRange: `$${lead.priceRange.low}-$${lead.priceRange.high}`,
  leadScore: lead.ai.leadScore,
  qualification: lead.ai.qualification,
  clientId: lead.clientId,
  smsResponse: lead.ai.smsToCustomer
};

// For now, just pass through — will add DB storage later
return [{ json: logEntry }];

const input = $input.first().json;

const serviceMap = {
  'emergency-leak': 'Emergency / Leak',
  'drain-cleaning': 'Drain Cleaning',
  'water-heater-tank': 'Water Heater (Tank)',
  'water-heater-tankless': 'Water Heater (Tankless)',
  'toilet': 'Toilet',
  'faucet-fixture': 'Faucet / Fixture',
  'garbage-disposal': 'Garbage Disposal',
  'sewer-line': 'Sewer Line',
  'slab-leak': 'Slab Leak',
  'gas-line': 'Gas Line',
  'repipe': 'Repipe',
  'water-softener': 'Water Softener',
  'water-test': 'Water Test',
  'filtration': 'Filtration / RO'
};

const urgencyMap = {
  'emergency': 'Emergency',
  'soon': 'Soon',
  'routine': 'Routine'
};

const notionPayload = {
  parent: { database_id: "32f12ff9-690a-816d-b4d7-c2bb569cd6b3" },
  properties: {
    "Name": { title: [{ text: { content: input.name || "Unknown" } }] },
    "Phone": { phone_number: input.phone || null },
    "Email": { email: input.email || null },
    "Service": { select: { name: serviceMap[input.service] || input.service || "Other" } },
    "Urgency": { select: { name: urgencyMap[input.urgency] || "Routine" } },
    "Zip Code": { rich_text: [{ text: { content: input.zipCode || "" } }] },
    "Preferred Time": { select: { name: input.preferredTime || "ASAP" } },
    "Status": { select: { name: "New" } },
    "Client": { rich_text: [{ text: { content: input.clientId || "demo" } }] },
    "Source": { select: { name: input.source || "direct" } },
    "Campaign": { rich_text: [{ text: { content: input.campaign || "" } }] },
    "Details": { rich_text: [{ text: { content: (input.details || "").substring(0, 2000) } }] },
    "Water Hardness": { number: input.waterHardness || 0 },
    "Language": { select: { name: input.lang || "en" } },
    "Date": { date: { start: new Date().toISOString() } }
  }
};

// Remove null email to avoid Notion error
if (!input.email) {
  delete notionPayload.properties["Email"];
}

return [{ json: { ...input, notionPayload } }];
